class Solution:
    def xorGame(self, nums):
        from functools import lru_cache
        base = tuple(sorted(nums))
        @lru_cache(maxsize=None)
        def alice_wins(state):
            x = 0
            for v in state:
                x ^= v
            if x == 0:
                return True
            for i in range(len(state)):
                rest = state[:i] + state[i + 1:]
                rx = 0
                for v in rest:
                    rx ^= v
                if rx == 0:
                    continue
                if not alice_wins(rest):
                    return True
            return False
        return alice_wins(base)

